import { Component, h, Prop, Element } from '@stencil/core';

@Component({
  tag: 'wdpr-read-more',
  shadow: true,
})
export class WdprReadMore {
  @Element() el: HTMLElement;

  private contentRef: HTMLDivElement;

  /** Show divider line above content */
  @Prop() showTopDivider = false;

  /** Show divider line below content */
  @Prop() showBottomDivider = false;

  /** Whether the content is expanded or collapsed */
  @Prop({ mutable: true }) expanded = false;

  /** Whether the read more button is disabled */
  @Prop() disabled = false;

  /** Text for the expand button */
  @Prop() expandLabel = 'Read More';

  /** Text for the collapse button */
  @Prop() collapseLabel = 'Read Less';

  private _toggleExpanded = (event: Event) => {
    event.preventDefault();
    const wasExpanded = this.expanded;
    this.expanded = !this.expanded;
    
    // Move focus to content when expanding for accessibility
    if (!wasExpanded && this.contentRef) {
      requestAnimationFrame(() => {
        this.contentRef.focus();
      });
    }
  };

  render() {
    return (
      <div class="flex flex-col gap-200 p-200">
        {this.showTopDivider && <wdpr-divider />}

        <div class="transition-all duration-300 text-text-body body-large">
          <div 
            class={{ hidden: this.expanded }} 
            inert={this.expanded} 
            aria-hidden={this.expanded ? 'true' : undefined}
          >
            <slot name="collapsed" />
          </div>
          <div 
            ref={(el) => (this.contentRef = el)}
            tabindex={this.expanded ? -1 : undefined}
            class={{ 'hidden': !this.expanded, 'focus:outline-none': true }} 
            inert={!this.expanded}
            aria-hidden={!this.expanded ? 'true' : undefined}
          >
            <slot name="expanded" />
          </div>
        </div>

        <wdpr-read-more-button 
          expanded={this.expanded}
          disabled={this.disabled}
          onClick={this._toggleExpanded}>
            {this.expanded ? this.collapseLabel : this.expandLabel}
        </wdpr-read-more-button>

        {this.showBottomDivider && <wdpr-divider />}
      </div>
    );
  }
}
